import{_ as e,o as s,c as n,a2 as t}from"./chunks/framework.DCVnL8g5.js";const b=JSON.parse('{"title":"Lenguaje ubicuo","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/02-lenguaje-ubicuo.md","filePath":"full-stack/arquitectura/ddd/02-lenguaje-ubicuo.md","lastUpdated":1782521464000}'),i={name:"full-stack/arquitectura/ddd/02-lenguaje-ubicuo.md"};function o(l,a,c,p,r,u){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="lenguaje-ubicuo" tabindex="-1">Lenguaje ubicuo <a class="header-anchor" href="#lenguaje-ubicuo" aria-label="Permalink to &quot;Lenguaje ubicuo&quot;">​</a></h1><p>El lenguaje ubicuo es el vocabulario compartido entre negocio, producto, diseno y desarrollo. Si una palabra significa cosas distintas para cada equipo, el software acabara reflejando esa confusion.</p><h2 id="objetivo" tabindex="-1">Objetivo <a class="header-anchor" href="#objetivo" aria-label="Permalink to &quot;Objetivo&quot;">​</a></h2><p>Conseguir que conversaciones, tickets, diagramas, tests y codigo usen los mismos terminos.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Negocio: una matricula puede estar pendiente, activa o cancelada.</span></span>
<span class="line"><span>Codigo: EnrollmentStatus = pending | active | cancelled</span></span>
<span class="line"><span>Tests: cannot cancel an active enrollment after certificate is issued</span></span></code></pre></div><h2 id="detectar-terminos-importantes" tabindex="-1">Detectar terminos importantes <a class="header-anchor" href="#detectar-terminos-importantes" aria-label="Permalink to &quot;Detectar terminos importantes&quot;">​</a></h2><p>Presta atencion a:</p><ul><li>Sustantivos: pedido, factura, alumno, curso, reserva.</li><li>Verbos: confirmar, cancelar, publicar, aprobar, liquidar.</li><li>Estados: pendiente, activo, bloqueado, vencido.</li><li>Reglas: no se puede, solo si, excepto cuando.</li><li>Eventos: pedido confirmado, factura pagada, curso publicado.</li></ul><h2 id="evitar-traducciones-pobres" tabindex="-1">Evitar traducciones pobres <a class="header-anchor" href="#evitar-traducciones-pobres" aria-label="Permalink to &quot;Evitar traducciones pobres&quot;">​</a></h2><p>Mal:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DataManager</span></span>
<span class="line"><span>ProcessService</span></span>
<span class="line"><span>Item</span></span>
<span class="line"><span>Object</span></span>
<span class="line"><span>Status = 1</span></span></code></pre></div><p>Mejor:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>InvoiceIssuer</span></span>
<span class="line"><span>PaymentCapture</span></span>
<span class="line"><span>Enrollment</span></span>
<span class="line"><span>Course</span></span>
<span class="line"><span>InvoiceStatus = overdue</span></span></code></pre></div><h2 id="lenguaje-por-contexto" tabindex="-1">Lenguaje por contexto <a class="header-anchor" href="#lenguaje-por-contexto" aria-label="Permalink to &quot;Lenguaje por contexto&quot;">​</a></h2><p>Una palabra puede significar cosas distintas en contextos distintos.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Catalogo: Course es un producto publicable.</span></span>
<span class="line"><span>Aprendizaje: Course es una experiencia con progreso.</span></span>
<span class="line"><span>Facturacion: Course es una linea facturable.</span></span></code></pre></div><p>No fuerces un unico modelo global si el negocio no piensa asi.</p><h2 id="tests-como-lenguaje" tabindex="-1">Tests como lenguaje <a class="header-anchor" href="#tests-como-lenguaje" aria-label="Permalink to &quot;Tests como lenguaje&quot;">​</a></h2><p>Los tests son una forma excelente de fijar lenguaje:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>given draft course</span></span>
<span class="line"><span>when instructor publishes it</span></span>
<span class="line"><span>then course becomes available for enrollment</span></span></code></pre></div><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Los nombres del codigo aparecen en conversaciones reales.</li><li>Los estados tienen significado de negocio.</li><li>Los tests describen reglas, no detalles tecnicos.</li><li>Los terminos ambiguos se documentan.</li><li>Cada bounded context puede tener su propio vocabulario.</li></ul>`,22)])])}const h=e(i,[["render",o]]);export{b as __pageData,h as default};
